INSERT INTO MD_BCR_READING_HISTORY (
        DEVICE_AREA_CODE,
        BARCODE,
        WORK_ID
)
SELECT
    #{deviceAreaCode},
    #{barcode},
    #{workId}
WHERE NOT EXISTS (
    SELECT 1
    FROM MD_BCR_READING_HISTORY
    WHERE DEVICE_AREA_CODE = #{deviceAreaCode}
    AND BARCODE = #{barcode}
    AND WORK_ID = #{workId}
)
